#!/usr/bin/env perl
use strict;
use warnings;
no warnings 'portable';
use File::Path qw(make_path);
use File::Basename;

my $MINIGIT_DIR = '.minigit';
my $OBJECTS_DIR = "$MINIGIT_DIR/objects";
my $COMMITS_DIR = "$MINIGIT_DIR/commits";
my $INDEX_FILE  = "$MINIGIT_DIR/index";
my $HEAD_FILE   = "$MINIGIT_DIR/HEAD";

sub minihash {
    my ($data) = @_;
    # Use Math::BigInt to handle 64-bit arithmetic portably
    my $h = 1469598103934665603;
    my $mod = 2**64;
    my @bytes = unpack('C*', $data);
    for my $b (@bytes) {
        $h ^= $b;
        # Use no integer to avoid signed overflow issues
        # We need unsigned 64-bit multiplication mod 2^64
        $h = _mulmod($h, 1099511628211, $mod);
    }
    return sprintf('%016x', $h);
}

sub _mulmod {
    my ($a, $b, $mod) = @_;
    # For systems with 64-bit integers, we can use direct multiplication
    # but need to handle overflow. Use the fact that Perl can do big int math
    # with 'use integer' or by splitting.
    # Actually on 64-bit Perl, we can use native integers if we're careful.
    # Let's split the multiplication to avoid overflow.

    # a * b mod 2^64
    # Split b into high and low 32 bits
    my $b_lo = $b & 0xFFFFFFFF;
    my $b_hi = ($b >> 32) & 0xFFFFFFFF;

    # a * b = a * b_hi * 2^32 + a * b_lo
    # We need mod 2^64 for both parts

    # a * b_lo
    my $a_lo = $a & 0xFFFFFFFF;
    my $a_hi = ($a >> 32) & 0xFFFFFFFF;

    # Full multiplication using 32-bit parts
    my $r0 = $a_lo * $b_lo;
    my $r1 = $a_hi * $b_lo + $a_lo * $b_hi;

    # Combine: result = r1 * 2^32 + r0, mod 2^64
    my $result = (($r1 & 0xFFFFFFFF) << 32) + $r0;
    # Mask to 64 bits
    $result &= 0xFFFFFFFFFFFFFFFF;
    return $result;
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path($OBJECTS_DIR);
    make_path($COMMITS_DIR);
    open(my $fh, '>', $INDEX_FILE) or die "Cannot create index: $!\n";
    close($fh);
    open($fh, '>', $HEAD_FILE) or die "Cannot create HEAD: $!\n";
    close($fh);
}

sub cmd_add {
    my ($file) = @_;
    unless (defined $file && -e $file) {
        print "File not found\n";
        exit 1;
    }

    # Read file content
    open(my $fh, '<:raw', $file) or die "Cannot read $file: $!\n";
    my $content = do { local $/; <$fh> };
    close($fh);

    my $hash = minihash($content);

    # Store blob
    my $blob_path = "$OBJECTS_DIR/$hash";
    unless (-e $blob_path) {
        open(my $ofh, '>:raw', $blob_path) or die "Cannot write blob: $!\n";
        print $ofh $content;
        close($ofh);
    }

    # Update index - add filename if not already present
    my @entries;
    if (-f $INDEX_FILE) {
        open(my $ifh, '<', $INDEX_FILE) or die "Cannot read index: $!\n";
        @entries = <$ifh>;
        close($ifh);
        chomp @entries;
        @entries = grep { $_ ne '' } @entries;
    }

    unless (grep { $_ eq $file } @entries) {
        push @entries, $file;
    }

    open(my $ofh, '>', $INDEX_FILE) or die "Cannot write index: $!\n";
    for my $e (@entries) {
        print $ofh "$e\n";
    }
    close($ofh);
}

sub cmd_commit {
    my ($message) = @_;

    # Read index
    my @entries;
    if (-f $INDEX_FILE) {
        open(my $ifh, '<', $INDEX_FILE) or die "Cannot read index: $!\n";
        @entries = <$ifh>;
        close($ifh);
        chomp @entries;
        @entries = grep { $_ ne '' } @entries;
    }

    if (!@entries) {
        print "Nothing to commit\n";
        exit 1;
    }

    # Read HEAD
    my $parent = '';
    if (-f $HEAD_FILE) {
        open(my $hfh, '<', $HEAD_FILE) or die "Cannot read HEAD: $!\n";
        $parent = <$hfh>;
        close($hfh);
        $parent = '' unless defined $parent;
        chomp $parent;
    }
    $parent = 'NONE' if $parent eq '';

    my $timestamp = time();

    # Sort filenames
    my @sorted = sort @entries;

    # Build file list with blob hashes
    my @file_lines;
    for my $fname (@sorted) {
        # Read current file content and hash it
        open(my $fh, '<:raw', $fname) or die "Cannot read $fname: $!\n";
        my $content = do { local $/; <$fh> };
        close($fh);
        my $hash = minihash($content);
        push @file_lines, "$fname $hash";
    }

    # Build commit content
    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";
    for my $fl (@file_lines) {
        $commit_content .= "$fl\n";
    }

    my $commit_hash = minihash($commit_content);

    # Write commit file
    open(my $cfh, '>', "$COMMITS_DIR/$commit_hash") or die "Cannot write commit: $!\n";
    print $cfh $commit_content;
    close($cfh);

    # Update HEAD
    open(my $hfh, '>', $HEAD_FILE) or die "Cannot write HEAD: $!\n";
    print $hfh $commit_hash;
    close($hfh);

    # Clear index
    open(my $ifh, '>', $INDEX_FILE) or die "Cannot clear index: $!\n";
    close($ifh);

    print "Committed $commit_hash\n";
}

sub cmd_log {
    # Read HEAD
    my $current = '';
    if (-f $HEAD_FILE) {
        open(my $hfh, '<', $HEAD_FILE) or die "Cannot read HEAD: $!\n";
        $current = <$hfh>;
        close($hfh);
        $current = '' unless defined $current;
        chomp $current;
    }

    if ($current eq '') {
        print "No commits\n";
        return;
    }

    my $first = 1;
    while ($current ne '' && $current ne 'NONE') {
        my $commit_path = "$COMMITS_DIR/$current";
        unless (-f $commit_path) {
            last;
        }

        open(my $cfh, '<', $commit_path) or die "Cannot read commit: $!\n";
        my @lines = <$cfh>;
        close($cfh);
        chomp @lines;

        my ($parent, $timestamp, $message);
        for my $line (@lines) {
            if ($line =~ /^parent: (.*)$/) {
                $parent = $1;
            } elsif ($line =~ /^timestamp: (.*)$/) {
                $timestamp = $1;
            } elsif ($line =~ /^message: (.*)$/) {
                $message = $1;
            }
        }

        print "\n" unless $first;
        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";

        $first = 0;
        $current = $parent;
    }
}

# Main
my $cmd = shift @ARGV;
unless (defined $cmd) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($cmd eq 'commit') {
    # Parse -m "message"
    my $flag = shift @ARGV;
    my $message = shift @ARGV;
    if (!defined $flag || $flag ne '-m' || !defined $message) {
        print "Usage: minigit commit -m \"message\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($cmd eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $cmd\n";
    exit 1;
}

