    close($cfh);

    # Update HEAD
    open(my $hfh, '>', $HEAD_FILE) or die "Cannot write HEAD: $!\n";
    print $hfh $commit_hash;
    close($hfh);

    # Clear index
    open(my $ifh, '>', $INDEX_FILE) or die "Cannot clear index: $!\n";
    close($ifh);

    print "Committed $commit_hash\n";
}

